VALUES
  ('dietitian-moex-07944', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於社區化長期照護的精神與策略，下列敘述何者正確？', '["社區化的作法儘量去機構化，而強化醫院居家照護的個人服務體系", "民眾意願上，在地（宅）老化優先於機構照護，應將機構照護融入居家照護", "機構照護的資源豐沛且專業素質高，應優先於居家護理的高成本服務", "社區化長期照護的策略，是鼓勵社區民眾參與學習照護年長父母的能力，多自行照護以維持敬老文化 和價值觀"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07945', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某項研究在20個醫學中心召募5000位婦女後，隨機將其分成兩組，其中一組攝取低脂飲食，另一組維 持原有飲食。十年之後，分析兩組罹患癌症或心血管疾病的發生率，此種研究設計稱為：', '["世代研究", "病例對照研究", "營養介入實驗", "橫斷面相關性研究"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07946', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '97年度台北市衛生局共舉辦45場社區營養教育。此種評價方式稱為：', '["效率（Efficiency）", "效果（Effort）", "效能（Effectiveness）", "效益（Benefit）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07947', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據國小學童營養健康狀況調查（2001-2002）的血液營養素分析結果顯示，國小學童之維生素缺乏（包 含邊緣缺乏）盛行率，以那一種維生素最低？', '["維生素B", "維生素B", "維生素B", "葉酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07948', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '2 6', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07949', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列敘述何者符合2001-2002台灣國小學童飲食營養知識、態度與行為調查結果？', '["每天吃早餐、午餐和晚餐的比例均在九成以上", "4-6年級有1/4自己準備早餐", "澎湖地區4-6年級學童比其他地區學童最常表現節制飲食行為", "學童同意選食應以健康為首要考量，在口味或享受上做一些犧牲"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07950', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據老人營養健康狀況調查（1999-2000）的結果發現，國內65歲以上老人之糖尿病盛行率約多少百分比？', '["10%-11%", "18%-19%", "35%-36%", "58%-60%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07951', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「臺灣地區第一次國民營養健康狀況變遷調查（NAHSIT, 1993-1996）」及「老人營養現況-臺灣地區 老人營養健康狀況1999-2000」調查資料顯示，國人肥胖盛行率有逐年增加的趨勢。若從疾病自然史的觀 點，臺灣地區人民可能處於那一個階段？', '["易感受期", "臨床前期", "臨床期", "後臨床期"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07952', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關母乳代用品在醫院的使用原則，下列何者錯誤？', '["不可在保健機構留置母乳代用品樣品，供嬰幼兒使用", "不可向保健工作者提供與母乳代用品相關之科學文獻或具有實證之資料", "不可以文宣宣傳人工餵養", "不可在母乳代用品標籤上印上嬰兒圖樣"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07953', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '世界衛生組織（WHO）認為，微量營養素缺乏症中，下列那三項對於目前全球公共衛生議題的影響最大？', '["Vitamin A deficiency", "Vitamin D deficiency", "Iron deficiency", "Calcium deficiency  ⑤Iodine deficiency"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
